INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$CRM & Contact Management$q$, $q$Centralized contact records with tagging, segmentation, and activity history keep sales, marketing, and support context in one place.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Marketing Automation & Campaign Builder$q$, $q$A visual, drag-and-drop builder lets businesses trigger emails, tasks, and pipeline changes automatically based on customer behavior.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Sales Pipeline Management$q$, $q$A Kanban-style pipeline view tracks deals from first contact through close, with automated reminders for follow-up.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Email Marketing$q$, $q$Template-based email campaigns and automated sequences support lead nurturing and ongoing customer communication.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Text (SMS) Marketing$q$, $q$Two-way text messaging lets businesses reach leads and customers directly from the same contact record used for email.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Landing Pages & Web Forms$q$, $q$Built-in landing page and form tools capture new leads directly into the CRM without needing a separate page builder.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Appointments & Scheduling$q$, $q$Calendar-synced booking pages let prospects and clients schedule meetings without back-and-forth emails.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Invoicing & Payments$q$, $q$Quotes, invoices, and online payment collection let businesses manage billing alongside the rest of the customer relationship.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Mobile App$q$, $q$iOS and Android apps let teams call, text, and manage contacts and tasks while away from the desktop.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Reporting & Analytics$q$, $q$Dashboards track campaign performance, sales activity, and pipeline health to guide follow-up priorities.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$All-in-one platform combining CRM, marketing automation, sales pipeline, and invoicing$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Powerful visual automation builder for lead nurturing and follow-up$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Built specifically for small-business workflows like appointments and quotes$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Mobile app supports calling and texting contacts on the go$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Long track record and mature feature set inherited from Infusionsoft$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$No free plan, and pricing scales with both contacts and users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Learning curve for setting up the automation builder effectively$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Optional onboarding and coaching can add to the upfront cost$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Fewer enterprise-grade customization and reporting options than larger CRM suites$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Can feel like more platform than very small or early-stage businesses need$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Is Keap the same company as Infusionsoft?$q$, $q$Yes. Infusionsoft rebranded to Keap in 2019 after being founded in Chandler, Arizona in 2001, keeping the same core CRM and marketing automation product under a new name and simplified experience.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Does Keap offer a free plan?$q$, $q$Keap does not offer a permanent free plan, but it typically provides a free trial period so businesses can test the CRM, automation, and pipeline features before subscribing.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Who is Keap best suited for?$q$, $q$Keap is best suited for small businesses, coaches, consultants, agencies, and appointment-based service providers that want CRM, marketing automation, sales pipeline, and invoicing in one connected platform.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Does Keap have a mobile app?$q$, $q$Yes, Keap offers mobile apps for iOS and Android that let users manage contacts, make calls, and send texts from their phone.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Can Keap integrate with other tools?$q$, $q$Keap provides an API along with native and Zapier-based integrations, allowing it to connect with e-commerce platforms, webinar tools, and other small-business software.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Lead capture and nurturing for coaches and consultants$q$, $q$Automatically capture leads from landing pages and forms, then nurture them with email and text sequences until they book a call.$q$, $q$Coaches, consultants, and course creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Sales pipeline tracking for service businesses$q$, $q$Move prospects through a visual pipeline from initial inquiry to signed contract, with automated reminders for follow-up tasks.$q$, $q$Agencies and professional service firms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Appointment-driven client management$q$, $q$Let clients self-schedule appointments synced to a calendar, then follow up automatically with reminders and post-appointment messages.$q$, $q$Home-service businesses and appointment-based providers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Quoting, invoicing, and payment collection$q$, $q$Send quotes and invoices tied to the same contact record used for marketing and sales, then collect payment online.$q$, $q$Small business owners managing billing in-house$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Pro$q$, $q$From $199/month$q$, $q$Monthly or annual$q$, $q$["CRM with contact and lead management","Email marketing with automated sequences","Sales pipeline management","Landing pages and web forms","Appointments and invoicing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Max$q$, $q$From $289/month$q$, $q$Monthly or annual$q$, $q$["Everything in Pro","Advanced automation with if-then branching logic","Lead scoring","Advanced reporting","Recurring billing and subscription management"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Keap, formerly known as Infusionsoft, is a customer relationship management and marketing automation platform built specifically for small businesses. It combines contact management, email and text marketing, sales pipeline tracking, invoicing, and appointment scheduling into a single system, aiming to replace the patchwork of disconnected tools many small teams rely on.$q$, $q$The company was founded in Chandler, Arizona in 2001 and spent nearly two decades as Infusionsoft, a name closely associated with early marketing automation for small businesses, before rebranding to Keap in 2019. That rebrand also came with a simplified, more approachable product experience aimed at owner-operators rather than dedicated marketing departments.$q$, $q$Today Keap positions itself less as a marketing suite and more as an all-in-one client management and automation engine: capture a lead, nurture it automatically, move it through a sales pipeline, book the appointment, send the invoice, and follow up afterward, all tracked against a single contact record.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$who-keap-is-for$q$, $q$Who Keap Is For$q$, 2, ARRAY[$q$Keap is built for small businesses and solo operators who juggle sales, marketing, and client delivery without a dedicated ops or IT team. Coaches, consultants, agencies, home-service businesses, and other appointment- or project-based operations are the platform's core audience, since its automation tools are tuned around lead capture, follow-up, and booking rather than large-scale e-commerce catalogs.$q$, $q$It also suits businesses that have outgrown basic email tools or spreadsheets and want sales pipeline visibility, automated follow-up sequences, and invoicing in one place. Teams that value having a single vendor and a single contact record for marketing, sales, and billing, rather than stitching together separate point solutions, tend to get the most value from Keap.$q$, $q$Businesses willing to invest time in initial setup, and often the optional paid onboarding and coaching Keap offers, are better positioned to succeed with it. Because the automation builder is genuinely powerful, users who are prepared to map out their sales and follow-up processes up front generally see a stronger return than those looking for something to configure in an afternoon.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$who-should-avoid-keap$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Very early-stage businesses, freelancers testing an idea, or anyone with a tiny contact list and a limited budget may find Keap's pricing hard to justify compared with lighter, cheaper CRM or email tools built for that stage. There is no free plan, and cost scales with both contacts and users, which can make it feel expensive relative to simpler alternatives.$q$, $q$Larger enterprises with complex, multi-department marketing needs, advanced e-commerce catalogs, or requirements for deep custom reporting and data warehousing may find Keap's feature set more oriented toward small-business simplicity than enterprise scale. Organizations that need extensive role-based permissions, advanced segmentation at scale, or heavy customization may outgrow it.$q$, $q$Teams that are not willing to spend time learning the automation builder, or that expect a plug-and-play tool with zero setup, may find the learning curve and configuration effort frustrating. Businesses that primarily need a simple contact list or a single-channel email tool are usually better served by a lighter, purpose-built product.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Keap offers a CRM with contact and lead management, tagging, and segmentation, paired with a visual automation and campaign builder that can trigger emails, tasks, pipeline moves, and internal notifications based on customer behavior. Sales pipeline management gives teams a Kanban-style view of deals moving from lead to close.$q$, $q$Beyond core CRM functions, Keap includes email marketing with templates and sequences, text (SMS) marketing, landing pages and web forms for lead capture, and appointment scheduling that syncs with calendars. On the transactional side, it supports invoicing, online payments, quotes, and recurring billing, letting a business handle the full client lifecycle from first contact to paid invoice.$q$, $q$Reporting and analytics tools track campaign performance, sales activity, and pipeline health, while a mobile app extends contact management, calling, and text messaging to teams on the go. An API and native or Zapier-based integrations connect Keap to e-commerce platforms, webinar tools, and other software small businesses already use.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$the-keap-experience$q$, $q$The Keap Experience$q$, 2, ARRAY[$q$Getting started with Keap typically involves importing contacts, connecting a domain or email sending identity, and building out the first automated campaigns; Keap offers optional paid onboarding and coaching for businesses that want guided setup rather than a self-serve start. Many users describe an initial learning curve tied to the depth of the automation builder.$q$, $q$Once configured, day-to-day use centers on the contact record: viewing a lead's tags, pipeline stage, communication history, and upcoming tasks in one place, then letting automations handle routine follow-up so the business owner or sales team can focus on higher-value conversations and closing deals.$q$, $q$Long-time users, many carried over from the Infusionsoft era, generally value the platform's automation depth and all-in-one scope, while newer users weigh that power against the cost and setup time relative to simpler point solutions. Overall, the experience rewards businesses that treat Keap as a system to configure deliberately rather than a tool to switch on and forget.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Zero-knowledge encrypted vault$q$, $q$Passwords, passkeys, files, and identity data are encrypted and decrypted locally, so Keeper never has access to plaintext user data.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Cross-platform autofill$q$, $q$Browser extensions and mobile/desktop apps automatically fill saved logins, payment cards, and identity information.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Secure sharing and emergency access$q$, $q$Individual records or folders can be shared with permission controls, and trusted contacts can be granted emergency access to a vault.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$BreachWatch dark web monitoring$q$, $q$An optional add-on that scans the dark web for exposed credentials tied to stored accounts and alerts users to change compromised passwords.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Secure file storage$q$, $q$Encrypted storage for sensitive documents and files alongside passwords, available as an add-on with tiered storage limits.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Admin console and RBAC$q$, $q$Centralized administration for business and enterprise plans, including role-based access control, shared team folders, and policy enforcement.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$SSO and directory integrations$q$, $q$Support for SAML-based single sign-on, SCIM provisioning, and AD/LDAP directory sync for centralized user management.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Keeper Secrets Manager (KSM)$q$, $q$A secrets management module that secures API keys, database credentials, and other machine-to-machine secrets for DevOps workflows.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$KeeperPAM$q$, $q$A privileged access management module that extends Keeper's encryption architecture to privileged sessions and infrastructure credentials.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Security audit and password health$q$, $q$Reporting tools that flag weak, reused, or old passwords across a user's or organization's vaults.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Zero-knowledge architecture with strong independent security certifications$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Apps available across browsers, desktop, and mobile with consistent syncing$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Scales from a simple personal vault up to enterprise access and secrets management$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Family plan provides separate vaults for multiple household members under one subscription$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Admin console offers granular provisioning and role-based controls for IT teams$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Free plan is limited to one mobile device and a small number of stored records$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Some useful features, like dark web monitoring and extra file storage, cost extra as add-ons$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Business and enterprise configuration can require meaningful IT setup time$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Pricing structure with multiple tiers and add-ons can be confusing to compare at a glance$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Advanced modules like KeeperPAM and KSM add complexity that smaller teams may not need$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Is Keeper Security free to use?$q$, $q$Keeper offers a limited free plan restricted to one mobile device and a small number of stored records, along with a 30-day free trial of its paid personal and family plans.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Does Keeper support passkeys?$q$, $q$Yes, Keeper's vault can store and autofill passkeys alongside traditional passwords across supported browsers and devices.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$What is the difference between Keeper's personal and family plans?$q$, $q$The personal plan covers a single user's vault, while the family plan provisions separate encrypted vaults for multiple household members under one subscription, along with shared folders and emergency access.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Can Keeper access my stored passwords?$q$, $q$No. Keeper uses zero-knowledge encryption, meaning data is encrypted and decrypted on the user's device, and Keeper does not have the ability to view stored passwords or files in plaintext.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Does Keeper offer tools for businesses beyond password management?$q$, $q$Yes. Business and enterprise customers can add KeeperPAM for privileged access management and Keeper Secrets Manager for securing API keys and other machine credentials used in DevOps workflows.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Personal password and passkey management$q$, $q$An individual consolidates logins, payment cards, and identity details into one encrypted vault with autofill across devices.$q$, $q$Individual consumers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Household credential sharing$q$, $q$A family shares streaming, banking, and shopping logins securely across separate vaults under a single family plan, with emergency access set up for a trusted relative.$q$, $q$Families and households$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Company-wide credential governance$q$, $q$An IT team rolls out Keeper Business to centralize employee password practices, enforce shared team folders, and provision or deprovision access through SSO and SCIM.$q$, $q$Small and mid-sized business IT teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Privileged and machine credential security$q$, $q$An enterprise security team layers KeeperPAM and Keeper Secrets Manager onto its existing deployment to secure privileged sessions and API keys used in CI/CD pipelines.$q$, $q$Enterprise security and DevOps teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Free$q$, $q$Free$q$, $q$N/A$q$, $q$["Vault limited to one mobile device","Stores a small number of password and passkey records","Password generator and account recovery","No autofill or emergency access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Personal$q$, $q$From around $2-3/month$q$, $q$Billed annually$q$, $q$["Unlimited password and passkey storage","Unlimited devices and syncing","Browser extension and mobile/desktop autofill","Optional BreachWatch and secure file storage add-ons"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Family$q$, $q$From around $4-8/month$q$, $q$Billed annually$q$, $q$["Five separate private vaults for household members","All Personal plan features for each vault","Shared folders with permission controls","Emergency access and included file storage"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Business / Enterprise$q$, $q$Custom pricing per user, from a few dollars per user/month$q$, $q$Per user/month, billed annually$q$, $q$["Admin console with role-based access control","SSO, SCIM, and AD/LDAP provisioning","Shared team folders and delegated administration","Optional KeeperPAM and Keeper Secrets Manager add-ons"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Keeper Security is a password manager and digital vault built around zero-knowledge encryption, meaning passwords, files, and other secrets are encrypted and decrypted only on the user's device, never in a form Keeper itself can read. Founded in 2011 and headquartered in Chicago, the company has grown from a consumer password app into a broader cybersecurity platform covering personal vaults, family sharing, and enterprise-grade access and secrets management, with independent audits and government-focused certifications underpinning its security claims.$q$, $q$At its core, Keeper stores passwords, passkeys, payment cards, and identity records in an encrypted vault that syncs across browsers, desktops, and mobile devices. Autofill, a built-in password generator, and secure sharing links round out the everyday experience, while add-ons like BreachWatch dark web monitoring and encrypted file storage extend the vault into a more general-purpose security tool for everyday consumers as well as households managing shared accounts.$q$, $q$Beyond individual use, Keeper's business and enterprise tiers add an admin console, single sign-on, SCIM provisioning, role-based access control, and compliance reporting, positioning it alongside enterprise password and privileged access management vendors rather than only consumer password apps. Optional modules such as KeeperPAM and Keeper Secrets Manager extend the same encryption architecture to privileged sessions and machine-to-machine credentials used by DevOps teams, giving the platform a much broader footprint than a typical consumer-only password vault.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$who-keeper-is-for$q$, $q$Who Keeper Is For$q$, 2, ARRAY[$q$Keeper suits individuals and families who want a well-established password manager with strong third-party security certifications and cross-platform apps for browsers, phones, and desktops. Its family plan, which provisions separate encrypted vaults for multiple household members under one subscription, is a natural fit for households that want shared logins for streaming, banking, and shopping accounts without emailing passwords back and forth.$q$, $q$It's also a solid option for small and mid-sized businesses that have outgrown ad hoc password sharing and need an admin console to see who has access to what, enforce shared team folders, and offboard employees cleanly. IT teams that already manage SSO and directory services will find Keeper's SCIM, AD/LDAP, and SAML integrations useful for centralizing provisioning without rebuilding their existing identity workflows.$q$, $q$Larger organizations and managed service providers with compliance obligations (SOC 2, FedRAMP, HIPAA-adjacent requirements) are another good match, since Keeper markets its enterprise tier around auditability, role-based access control, and add-on privileged access management and secrets management modules for DevOps and infrastructure credentials. Regulated industries such as finance, healthcare, and government contracting are common adopters for exactly this reason.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Keeper's free tier is intentionally limited to a single mobile device and a small number of stored records, so users who want a fully-featured free password manager for daily use across multiple devices will likely find the free plan too restrictive and should budget for a paid tier from the start rather than expecting the free version to be a long-term solution.$q$, $q$Keeper's model of unbundling extras such as dark web monitoring and secure file storage as paid add-ons can also frustrate buyers who prefer a single all-inclusive price; those users may prefer a competitor that bundles more features into one flat subscription tier instead of layering optional purchases on top of a base plan.$q$, $q$Very small teams or solo users who don't need an admin console, compliance reporting, or provisioning integrations may find the business and enterprise tiers more complex and more expensive than necessary, and would be better served sticking with a personal or family plan, or a simpler consumer-focused password manager that skips enterprise administration entirely.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Keeper's foundation is its encrypted vault: passwords, passkeys, payment methods, and identity documents are stored with zero-knowledge encryption, synced across unlimited devices, and filled in automatically through browser extensions and mobile apps. A built-in password generator and security audit help users find and replace weak or reused credentials.$q$, $q$Sharing and collaboration features let individuals and teams securely share individual records or entire folders with permission controls, while family and business plans add shared folders, emergency access for trusted contacts, and delegated administration. Add-on modules extend the vault further: BreachWatch monitors the dark web for exposed credentials, KeeperChat offers encrypted messaging, and Secure File Storage keeps sensitive documents encrypted alongside passwords.$q$, $q$For businesses, the admin console centralizes user provisioning, policy enforcement, and reporting, with support for SSO, SCIM, and AD/LDAP directory sync. Enterprise customers can layer on KeeperPAM for privileged session management and Keeper Secrets Manager (KSM) for securing API keys, database credentials, and other secrets used by applications and CI/CD pipelines.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$the-keeper-experience$q$, $q$The Keeper Experience$q$, 2, ARRAY[$q$Day-to-day, Keeper feels like a conventional password manager: a browser extension and desktop or mobile app prompt to save new logins, autofill existing ones, and generate strong passwords, with biometric unlock (Face ID, fingerprint) reducing friction on mobile. The vault interface organizes records into folders and lets users flag favorites for quick access, and a security dashboard surfaces weak or reused passwords.$q$, $q$Setup and administration lean more heavily on documentation for business and enterprise customers, since configuring SSO, SCIM provisioning, and role-based policies through the admin console requires more IT involvement than the personal app. Keeper offsets this with 24/7 support and onboarding resources aimed at admins rolling the tool out across a workforce of any size.$q$, $q$Overall, the experience trades some of the visual simplicity of pure consumer password managers for the depth expected of a security platform: more settings, more optional modules, and more configuration surface, which power users and IT teams tend to view as a feature rather than a drawback once the initial setup is complete.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
