INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Mastery-based courses$q$, $q$Structured sequences in math, science, computing, economics, and humanities that unlock progressively as students demonstrate mastery of each skill.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Instructional video library$q$, $q$Thousands of short, free videos explaining concepts step by step, from basic arithmetic through multivariable calculus and beyond.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Interactive practice exercises$q$, $q$Auto-graded problem sets with instant feedback, hints, and worked solutions that adapt in difficulty as students improve.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Progress and mastery tracking$q$, $q$Dashboards showing skill-level mastery, streaks, and time spent, giving students and parents visibility into strengths and gaps.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Khan Academy Districts for teachers$q$, $q$Classroom tools for assigning content, monitoring student and class progress, and aligning practice to state and Common Core standards.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Official SAT practice$q$, $q$Free, personalized SAT preparation built in partnership with the College Board, including practice tied to PSAT diagnostic scores.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Khanmigo AI tutor$q$, $q$An AI chat tutor that guides students through problems with Socratic questioning rather than handing over direct answers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$AI tools for teachers$q$, $q$Khanmigo-powered lesson planning, rubric creation, and writing feedback tools designed to reduce teacher prep time.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Mobile apps$q$, $q$iOS and Android apps that mirror the web platform, letting students watch videos and practice skills from a phone or tablet.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Multilingual content$q$, $q$Courses and interface translated through Khan Academy's international partner network, extending access beyond English speakers.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Core platform is entirely free with no ads, paywalls, or hidden costs for students or families$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Mastery-based structure lets learners fill gaps at their own pace instead of moving on before they're ready$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Broad subject coverage spans elementary math through early college and standardized test prep$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Official, free SAT practice partnership with the College Board is a genuinely valuable, unique feature$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Reputable nonprofit backing with a long track record and no obligation to monetize student data through ads$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$No live instructors or accredited certificates, so it can't replace formal schooling or credentialed courses$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Content stops short of advanced, graduate-level, or highly specialized professional subjects$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$The richest Khanmigo AI tutoring features require a paid subscription for individual (non-teacher) users$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Self-paced format requires strong self-motivation and can be hard for some students to stick with unsupervised$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Teacher and district features add a learning curve on top of the simpler student-facing experience$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Is Khan Academy really free?$q$, $q$Yes. The core Khan Academy platform, including all videos, practice exercises, courses, and official SAT prep, is completely free for students, parents, and teachers, funded by donations rather than subscriptions.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$What is Khanmigo and does it cost money?$q$, $q$Khanmigo is Khan Academy's AI tutor and teaching assistant. It's free for U.S. teachers through a Microsoft-backed partnership, while individual learners and parents pay a small monthly or annual fee, and schools/districts can license it at scale for a per-student price.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Who created Khan Academy and when?$q$, $q$Khan Academy was founded in 2008 by Salman Khan, who started making tutoring videos for family members before turning the project into a full nonprofit education organization.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Does Khan Academy offer certificates or college credit?$q$, $q$Khan Academy does not issue accredited diplomas or college credit on its own, though its content is widely used to prepare for exams like the SAT and to supplement school curricula.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Is Khan Academy suitable for homeschooling?$q$, $q$Yes. Many homeschooling families use Khan Academy as a free, structured core curriculum for math and other subjects, often supplementing it with other resources for subjects it doesn't cover in depth.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Filling gaps in math fundamentals$q$, $q$Students who are behind grade level use mastery-based practice to rebuild foundational skills at their own pace before tackling grade-level material.$q$, $q$K-12 students and parents$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Free, structured homeschool curriculum$q$, $q$Families build a no-cost core curriculum around Khan Academy's course sequences, tracking progress across subjects without paying for textbooks or software.$q$, $q$Homeschooling families$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Classroom supplement and progress monitoring$q$, $q$Teachers assign targeted practice, track class-wide mastery, and identify students who need extra support using Khan Academy Districts dashboards.$q$, $q$K-12 teachers and schools$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Free official SAT preparation$q$, $q$Students link diagnostic or PSAT scores to get a personalized, College Board-backed SAT practice plan at no cost.$q$, $q$High school students preparing for college admissions$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Khan Academy (core platform)$q$, $q$Free$q$, $q$N/A$q$, $q$["All courses, videos, and practice exercises","Official SAT practice","Progress and mastery tracking","Available on web, iOS, and Android"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Khanmigo for Teachers$q$, $q$Free$q$, $q$N/A$q$, $q$["AI-assisted lesson planning","Rubric and feedback generation","Available to eligible U.S. teachers via Microsoft partnership","Classroom-focused AI tools"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Khanmigo for Individuals$q$, $q$From $4/month$q$, $q$Monthly or annual$q$, $q$["AI tutor for personalized help","Socratic-style guided problem solving","Available to parents and individual learners","Annual billing discount available"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$Khan Academy Districts / Khanmigo for Schools$q$, $q$Custom pricing$q$, $q$Annual$q$, $q$["District-wide teacher and student dashboards","Bulk Khanmigo AI access per student","Standards alignment and reporting","Dedicated support for school deployments"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Khan Academy is a nonprofit education organization founded in 2008 by Salman Khan, born out of a series of tutoring videos he made for his cousins. What began as a small YouTube channel has grown into one of the most widely used online learning platforms in the world, covering subjects from arithmetic and algebra to calculus, biology, chemistry, physics, economics, computer programming, grammar, art history, and standardized test prep like the SAT. The organization is headquartered in Mountain View, California, and operates as a 501(c)(3) nonprofit rather than a for-profit education company.$q$, $q$The platform is built around short instructional videos paired with interactive practice exercises, and it uses mastery-based learning: students work through problems at their own pace, get instant feedback, and unlock more advanced material only after demonstrating understanding. Progress is tracked automatically, giving students, parents, and teachers a clear picture of strengths and gaps.$q$, $q$Everything on Khan Academy's core platform is free, funded through philanthropic donations, grants, and corporate partnerships rather than tuition or subscriptions. In recent years, Khan Academy has layered in Khanmigo, an AI-powered tutor and teaching assistant, which is free for teachers through a Microsoft partnership and available to individual learners and parents for a modest monthly fee. This dual structure lets the organization keep its foundational mission of free access intact while still experimenting with newer, AI-driven tools that carry real infrastructure costs.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$who-its-for$q$, $q$Who Khan Academy Is For$q$, 2, ARRAY[$q$Khan Academy is best suited to K-12 students who need extra practice or a different explanation than the one they got in class, homeschooling families looking for a structured, no-cost curriculum, and self-directed learners of any age who want to revisit math, science, or humanities fundamentals. Its mastery system rewards patience and repetition, which makes it especially valuable for students who are behind grade level and need to rebuild foundational skills without judgment.$q$, $q$Teachers and schools are a major audience as well. Khan Academy Districts gives educators dashboards to assign practice, monitor class-wide progress, and identify students who are struggling on specific skills, all layered on top of the same free content used by individual learners. Test-prep students also rely heavily on the platform, particularly for official, College Board-partnered SAT practice.$q$, $q$Parents supporting a child's learning at home, adult learners returning to brush up on math or personal finance, and anyone studying for standardized tests on a tight budget all find a natural fit here, since the core experience requires no payment and no long-term commitment. International learners also benefit from Khan Academy's localized content, which is translated and adapted by partner organizations in dozens of countries.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$who-should-avoid$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Khan Academy is not built for learners who need live instruction, cohort-based accountability, or a credentialed degree or certificate at the end of their studies. There are no instructors to ask questions of in real time (outside of Khanmigo's AI chat), no accredited diplomas, and no formal grading tied to an institution unless a school specifically adopts the platform.$q$, $q$Advanced or highly specialized learners, such as graduate students, professionals seeking niche technical certifications, or people studying subjects outside Khan Academy's core K-12-through-early-college catalog, will likely outgrow the content quickly and need a more specialized platform. Corporate teams looking for workplace skills training or compliance courses are also better served elsewhere.$q$, $q$Learners who want a fully AI-tutored, highly personalized experience beyond basic hints and explanations should note that the richest Khanmigo features carry a separate monthly cost for non-teacher users, and some district-level AI features require an institutional purchase rather than being freely available to individuals. Anyone expecting one-on-one human mentorship, live cohorts, or a job-placement-style bootcamp experience will find the self-paced, video-and-exercise format a poor match for those expectations.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Khan Academy offers thousands of instructional videos and interactive practice problems spanning math (from early elementary through multivariable calculus), science, computing, economics, arts and humanities, and test prep, all organized into mastery-based course sequences with progress tracking, badges, and skill mastery levels.$q$, $q$For classrooms, Khan Academy Districts adds teacher dashboards, assignment tools, real-time class and student progress reports, and alignment to state and Common Core standards, making it easy for schools to integrate the free content into daily instruction. Official, free SAT practice built with the College Board is another standout feature, including personalized practice recommendations based on PSAT or diagnostic scores.$q$, $q$Khanmigo extends the platform with an AI tutor that can walk students through problems Socratically rather than just giving answers, plus AI tools for teachers such as lesson planning, rubric generation, and writing feedback. Content is also localized into multiple languages through Khan Academy's international partner network, extending reach well beyond English-speaking learners.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', $q$experience$q$, $q$The Khan Academy Experience$q$, 2, ARRAY[$q$Using Khan Academy typically starts with creating a free account, selecting a course or letting the platform recommend one based on a placement check, and then moving through short videos interspersed with practice sets. The interface is clean and distraction-light, with clear visual indicators of mastery so learners always know what to tackle next.$q$, $q$The experience feels encouraging rather than punitive: mistakes trigger hints and worked-through explanations instead of just a red X, and streaks, points, and mastery badges provide light gamification without overwhelming the learning itself. On mobile, the iOS and Android apps mirror the web experience, letting students study offline-friendly video content and practice on the go.$q$, $q$For teachers, logging into a district or classroom account surfaces a dashboard of assignments and student performance rather than the learner-facing course catalog, and Khanmigo can be toggled on for AI-assisted planning and in-classroom tutoring support. Overall, the day-to-day experience is intentionally simple: pick a skill, watch or read a short explanation, practice until mastery, and move on.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3272c3b2-7b50-4f01-838c-a33fa1daae36', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
