INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Performance Reviews$q$, $q$Customizable review cycles with 360-degree feedback and competency-based questions for structured performance evaluation.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Goals & OKRs$q$, $q$Cascade company, team, and individual goals so progress and alignment can be tracked over time.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Employee Engagement Surveys$q$, $q$Pulse and eNPS surveys with benchmarking and heatmaps to measure and track workforce sentiment.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$1:1 Meetings$q$, $q$Shared agendas, notes, and talking points that help managers and direct reports run consistent check-ins.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Career Development$q$, $q$Career tracks, competency matrices, and individual development plans that connect growth to performance data.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Compensation Management$q$, $q$Merit cycles and pay-band planning tools that tie compensation decisions to performance and goal data.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Core HRIS$q$, $q$Centralized employee records, org charts, and workforce reporting as the data backbone for other modules.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Lattice AI$q$, $q$AI-assisted review writing, survey analysis, goal summarization, and an AI agent for answering common HR questions.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$People Analytics$q$, $q$Dashboards that surface trends across performance, engagement, and turnover to inform people decisions.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Integrations$q$, $q$Native and API-based connections to common HRIS, payroll, calendar, and communication tools.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Combines performance reviews, goals, engagement surveys, and career development in one connected platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Widely regarded as intuitive and easy to use for both managers and employees, not just HR admins$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$AI-assisted features help speed up writing reviews and summarizing survey and goal data$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Modular product structure lets companies choose only the modules relevant to their needs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Broad integration ecosystem with common HRIS, payroll, and workplace communication tools$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Pricing is not published transparently and requires a sales conversation to get an exact quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Annual, quote-based contracts can make it less accessible for very small or self-serve buyers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Some capabilities, such as AI features and compensation planning, may require add-on modules at extra cost$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Configuring review cycles, goal structures, and permissions can take real setup time for larger organizations$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Sales-led buying process may feel heavier than lightweight, single-purpose HR point tools$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$What is Lattice used for?$q$, $q$Lattice is a people management platform used for performance reviews, goal and OKR tracking, employee engagement surveys, 1:1 meetings, career development, and compensation planning.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$How much does Lattice cost?$q$, $q$Lattice does not publish full self-serve pricing; it sells modular products on a per-seat, annually billed basis, with exact costs depending on which modules and seat count a company selects, quoted through its sales team.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Does Lattice offer a free trial?$q$, $q$Lattice is primarily a sales-led platform aimed at HR teams, and it typically offers guided demos rather than a broadly advertised self-serve free trial; prospective customers should contact Lattice directly to confirm current options.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Does Lattice have a mobile app?$q$, $q$Yes, Lattice offers mobile apps for iOS and Android that let employees and managers handle 1:1s, feedback, praise, and surveys from their phone.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$What size companies use Lattice?$q$, $q$Lattice is used by companies ranging from growing startups to large enterprises, with its modular product and pricing structure allowing organizations to scale usage as their HR needs grow.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Performance Review Cycles$q$, $q$HR teams run structured, recurring performance reviews with 360-degree feedback, competency questions, and calibration across the organization.$q$, $q$HR and People Operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$OKR and Goal Alignment$q$, $q$Leadership sets company-wide objectives and cascades them into team and individual goals that are tracked for progress throughout the year.$q$, $q$Executives and team leads$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Employee Engagement Measurement$q$, $q$People analytics teams deploy pulse and eNPS surveys and use benchmarking data to monitor and improve workforce sentiment over time.$q$, $q$People analytics and HR leaders$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Manager 1:1s and Career Development$q$, $q$Managers and employees use shared meeting agendas, feedback, and individual development plans to support ongoing career growth.$q$, $q$Managers and individual contributors$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$HRIS$q$, $q$Custom (reported around $10/seat/month)$q$, $q$Billed annually$q$, $q$["Centralized employee records","Org charts and workforce reporting","Foundation layer for other Lattice modules","Core admin permissions and data management"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Talent Management$q$, $q$Custom (reported around $11/seat/month)$q$, $q$Billed annually$q$, $q$["Performance reviews and 360-degree feedback","Goals and OKR tracking","Employee engagement surveys","1:1 meeting management","Career development plans"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Add-Ons$q$, $q$Custom (reported roughly $2-$6/seat/month depending on add-on)$q$, $q$Billed annually$q$, $q$["Payroll add-on","Time tracking add-on","Compensation management module"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom annual contract$q$, $q$["Volume-based seat pricing","Advanced admin controls and security","Dedicated implementation support","Custom integrations"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Lattice is a people management platform founded in 2015 and headquartered in San Francisco. It was built on the premise that annual performance reviews alone don't give managers or employees enough visibility into how work is actually going, so the product combines performance management, goal tracking, engagement measurement, and career development into one connected system rather than a set of disconnected point tools.$q$, $q$The platform is organized around a handful of core modules that companies can adopt together or separately: performance reviews and 360-degree feedback, goals and OKRs, employee engagement and pulse surveys, 1:1 meeting management, career development frameworks, compensation planning, and a core HRIS layer for storing employee records and org data. More recently, Lattice has layered AI capabilities on top of these modules to help HR teams and managers move faster on writing reviews, summarizing survey results, and tracking goal progress.$q$, $q$Because Lattice sells its products in a modular, quote-based way rather than through simple self-serve tiers, it tends to be positioned as a mid-market to enterprise people platform rather than a lightweight tool for very small teams. Buyers typically work with a Lattice sales team to configure which modules and seat counts fit their organization before signing an annual contract.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$who-lattice-is-for$q$, $q$Who Lattice Is For$q$, 2, ARRAY[$q$Lattice is best suited to HR and People Operations teams at growing or established companies that want to formalize performance management without stitching together several disconnected tools. Organizations that already run structured review cycles, OKR programs, or engagement surveys - or want to start doing so consistently - tend to get the most value from consolidating that work in one place.$q$, $q$It also fits companies that care about connecting performance data to career growth and compensation decisions, since Lattice's modules are designed to share data across review cycles, goal tracking, and merit or compensation planning. People analytics leaders who want dashboards and benchmarking across engagement, performance, and turnover trends are a natural audience as well.$q$, $q$Managers and employees who want a lighter-weight layer for 1:1s, feedback, and praise - not just a once-a-year review form - are also a good fit, since much of Lattice's day-to-day usage happens outside of formal review windows through ongoing feedback, recognition, and meeting tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Very small companies or early-stage startups without a dedicated HR function may find Lattice more platform than they currently need, especially given its sales-led, quote-based pricing and annual contract structure rather than simple self-serve monthly plans.$q$, $q$Teams that only need one narrow capability - for example, just pulse surveys, or just OKR tracking - may find a single-purpose tool cheaper and faster to set up than adopting Lattice's broader modular suite, particularly if they don't plan to use performance reviews, career development, or compensation planning together.$q$, $q$Organizations that want fully transparent, published pricing they can evaluate without a sales conversation may also find the process friction-heavy, since exact costs depend on which modules, add-ons, and seat counts are negotiated with Lattice's sales team.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Lattice offers structured performance reviews with customizable cycles, competency-based questions, and 360-degree feedback, alongside goals and OKR tracking that lets companies cascade objectives from company-wide priorities down to individual contributors and monitor progress over time.$q$, $q$Employee engagement is handled through pulse and eNPS surveys with benchmarking and reporting, while 1:1 meeting tools give managers and employees shared agendas, notes, and follow-up items. Career development features include competency matrices, career tracks, and individual growth plans, and a compensation management module supports merit cycles and pay-band planning.$q$, $q$Underneath these modules sits a core HRIS for centralized employee records, org charts, and workforce reporting, plus integrations with common payroll, calendar, and communication tools. Lattice has also added AI features, including an AI agent for answering HR questions, AI-assisted review writing and survey analysis, and tools for summarizing goal progress.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$the-lattice-experience$q$, $q$The Lattice Experience$q$, 2, ARRAY[$q$Day to day, using Lattice generally means logging into a web dashboard (or the iOS/Android mobile app) to check active goals, prep for an upcoming 1:1, give a teammate praise, or fill out a section of an in-progress review cycle. The interface is widely described as clean and approachable for non-HR employees, not just administrators.$q$, $q$For HR and People Ops admins, the experience centers on configuring review cycles, survey schedules, and goal structures, then monitoring completion and results through dashboards. Because performance, engagement, and goals data live in the same system, admins can look at trends - such as how engagement scores relate to turnover or goal completion - without exporting data between separate tools.$q$, $q$Implementation typically involves working with Lattice's team to decide which modules to turn on, migrate employee data into the HRIS layer, and configure review templates and permissions, which suits organizations willing to invest some setup time in exchange for a more unified long-term system.$q$]::text[], 4);
